package types

// The chain's protobuf types are generated by protoc-gen-go (protobuf v2),
// which registers them only in the protobuf-v2 global registry. cosmos-sdk
// v0.50's tx decoder runs unknownproto.RejectUnknownFields, which — for any
// NESTED concrete message field (not an Any) — resolves the field's type via
// gogoproto.MessageType, i.e. the *gogo* registry (codec/unknownproto/
// unknown_fields.go:164). A protoc-gen-go type is absent from that registry,
// so a tx carrying a Msg with a nested concrete message fails to decode with
// "failed to retrieve the message of type ...".
//
// For gov, MsgUpdateParams carries Params, and Params embeds these nested
// concrete (non-Any) message fields transitively: ParamChange,
// ResearchFundVoters, and CategoryConfig. All must be gogo-resolvable or a
// MsgUpdateParams tx fails to decode at CheckTx.
//
// Registration is EXPLICIT (not a protoregistry walk): Go runs a package's
// init() functions in lexical file order, so a walk in this file can run
// before the *.pb.go inits that populate the protobuf-v2 registry. Explicit
// references have no ordering dependence. Register every message a Msg
// embeds as a concrete (non-Any) field.

import (
	gogoproto "github.com/cosmos/gogoproto/proto"
)

func init() {
	for name, m := range map[string]gogoproto.Message{
		"zerone.gov.v1.Params":             (*Params)(nil),
		"zerone.gov.v1.ParamChange":        (*ParamChange)(nil),
		"zerone.gov.v1.ResearchFundVoters": (*ResearchFundVoters)(nil),
		"zerone.gov.v1.CategoryConfig":     (*CategoryConfig)(nil),
	} {
		if gogoproto.MessageType(name) == nil {
			gogoproto.RegisterType(m, name)
		}
	}
}
